optimized_federated_query:
# Smart Federated Query with UNION for Multiple Class Interpretations
# Each UNION branch uses different endpoints or predicates

SELECT ?actor ?film ?news ?x ?y
WHERE {
  # Scenario 1: ?film=film, ?actor=Person, ?x=Feature, ?y=Concept
  {
    SERVICE <http://localhost:8896/sparql/> {
      ?film <http://purl.org/dc/terms/title> "Tarzan" . # ?film:film
      ?film <http://data.linkedmdb.org/resource/movie/actor> ?actor . # ?film:film, ?actor:Person
    }
    SERVICE <http://localhost:8897/sparql/> {
      ?actor <http://www.w3.org/2002/07/owl#sameAs> ?x . # ?actor:Concept, ?x:Feature
      ?y <http://www.w3.org/2002/07/owl#sameAs> ?x . # ?y:Concept, ?x:Feature
      ?y <http://data.nytimes.com/elements/topicPage> ?news .
    }
  }

  UNION

  # Scenario 2: ?film=film, ?actor=Person, ?x=Drug, ?y=Concept
  {
    SERVICE <http://localhost:8895/sparql/> {
      ?actor <http://www.w3.org/2002/07/owl#sameAs> ?x . # ?actor:Drug, ?x:Drug
      ?y <http://www.w3.org/2002/07/owl#sameAs> ?x . # ?y:Drug, ?x:Drug
    }
    SERVICE <http://localhost:8896/sparql/> {
      ?film <http://purl.org/dc/terms/title> "Tarzan" . # ?film:film
      ?film <http://data.linkedmdb.org/resource/movie/actor> ?actor . # ?film:film, ?actor:Person
    }
    SERVICE <http://localhost:8897/sparql/> {
      ?y <http://data.nytimes.com/elements/topicPage> ?news .
    }
  }
}
LIMIT 1000
